document.addEventListener('DOMContentLoaded',function(){const faqItems=document.querySelectorAll('.faq-item');const formSubmit=document.getElementById('contact-form');const scrollElements=document.querySelectorAll('.fade-in-element, .fade-in-left, .fade-in-right, .stagger-animation');const testimonialSlider=document.querySelector('.testimonial-slider');const faqToggles=document.querySelectorAll('.faq-question');let isTestimonialAutoPlay=true;let slideIndex=0;const viewCounter=document.querySelector('.view-counter');let viewCount=viewCounter?parseInt(viewCounter.getAttribute('data-base-count'),10)||10:10;const recentPurchases=document.querySelector('.recent-purchases');const purchaseMessages=['東京都の方がホームページ制作を購入しました','大阪府の方がAIチャットボット開発を購入しました','名古屋市の方がSNSコンサルティングを始めました','福岡県の方がAIシステム導入を相談中です'];function handleScroll(){scrollElements.forEach(el=>{if(isElementInViewport(el)){el.classList.add('animate')}})}function isElementInViewport(el){const rect=el.getBoundingClientRect();return(rect.top<=window.innerHeight&&rect.bottom>=0)}function showNextSlide(){if(!testimonialSlider||testimonialSlider.children.length<=1)return;const testimonials=testimonialSlider.querySelectorAll('.testimonial');testimonials[slideIndex].style.display='none';slideIndex=(slideIndex+1)%testimonials.length;testimonials[slideIndex].style.display='block'}function randomActivity(){if(!viewCounter||!recentPurchases)return;const randomIncrease=Math.floor(Math.random()*2)+1;viewCount+=randomIncrease;viewCounter.textContent=`${viewCount}人が現在このページを閲覧中`;if(Math.random()>0.7&&purchaseMessages.length>0){const randomIndex=Math.floor(Math.random()*purchaseMessages.length);const purchaseNotification=document.createElement('div');purchaseNotification.className='purchase-notification';purchaseNotification.innerHTML=`<i class="fas fa-shopping-cart"></i> <span>${purchaseMessages[randomIndex]}</span>`;recentPurchases.appendChild(purchaseNotification);setTimeout(()=>{purchaseNotification.classList.add('show')},100);setTimeout(()=>{purchaseNotification.classList.remove('show');setTimeout(()=>{purchaseNotification.remove()},300)},5000)}}if(faqToggles){faqToggles.forEach(toggle=>{toggle.addEventListener('click',()=>{const faqItem=toggle.parentNode;const answer=faqItem.querySelector('.faq-answer');const toggleIcon=toggle.querySelector('.toggle-icon');faqItem.classList.toggle('active');if(faqItem.classList.contains('active')){toggleIcon.innerHTML='<i class="fas fa-minus"></i>'}else{toggleIcon.innerHTML='<i class="fas fa-plus"></i>'}})});faqToggles.forEach(toggle=>{const toggleIcon=toggle.querySelector('.toggle-icon');toggleIcon.innerHTML='<i class="fas fa-plus"></i>'})}if(formSubmit){formSubmit.addEventListener('submit',function(e){e.preventDefault();const submitBtn=formSubmit.querySelector('.btn-submit');const originalText=submitBtn.textContent;submitBtn.textContent='送信中...';submitBtn.disabled=true;setTimeout(()=>{const formAlert=document.createElement('div');formAlert.className='form-alert success';formAlert.textContent='お問い合わせありがとうございます。近日中にご連絡いたします。';formSubmit.appendChild(formAlert);formSubmit.reset();setTimeout(()=>{formAlert.remove();submitBtn.textContent=originalText;submitBtn.disabled=false},3000)},1500)})}window.addEventListener('scroll',handleScroll);handleScroll();setInterval(randomActivity,5000);if(testimonialSlider&&testimonialSlider.children.length>1){const testimonials=testimonialSlider.querySelectorAll('.testimonial');testimonials.forEach((t,i)=>{if(i!==0)t.style.display='none'});setInterval(()=>{if(isTestimonialAutoPlay)showNextSlide()},6000);testimonialSlider.addEventListener('mouseenter',()=>{isTestimonialAutoPlay=false});testimonialSlider.addEventListener('mouseleave',()=>{isTestimonialAutoPlay=true})}const floatingCta=document.querySelector('.floating-cta');let lastScrollTop=0;window.addEventListener('scroll',()=>{const currentScroll=window.pageYOffset||document.documentElement.scrollTop;if(currentScroll>lastScrollTop&&currentScroll>500){floatingCta.style.transform='translateY(150%)'}else{floatingCta.style.transform='translateY(0)'}lastScrollTop=currentScroll<=0?0:currentScroll});const cards=document.querySelectorAll('.card');cards.forEach(card=>{const originalTransform=card.style.transform;const originalBoxShadow=card.style.boxShadow;card.addEventListener('mouseenter',function(){this.style.transform='translateY(-15px)';this.style.boxShadow='0 15px 30px rgba(0,0,0,0.15)'});card.addEventListener('mouseleave',function(){this.style.transform=originalTransform;this.style.boxShadow=originalBoxShadow})});const navLinks=document.querySelectorAll('nav a, .footer-nav a');navLinks.forEach(link=>{link.addEventListener('click',function(e){const targetId=this.getAttribute('href');if(targetId.startsWith('#')&&targetId.length>1){e.preventDefault();const targetElement=document.querySelector(targetId);if(targetElement){const headerHeight=document.querySelector('header').offsetHeight;const targetPosition=targetElement.offsetTop-headerHeight;window.scrollTo({top:targetPosition,behavior:'smooth'})}}})})}); 